#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding nutrition-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    preferred_name:string! \
    gender_identity:string! \
    ethnicity:string! \
    preferred_language:string! \
    interpreter_required:string! \
    gp_name:string! \
    gp_practice:string! \
    referrer_name:string! \
    referrer_role:string! \
    --htmx

cargo loco generate scaffold assessment_anthropometric_measurements \
    assessment:references \
    current_weight_kg:double \
    usual_weight_kg:double \
    height_cm:double \
    bmi:double \
    mid_upper_arm_circumference_cm:double \
    waist_circumference_cm:double \
    unplanned_weight_loss:string! \
    weight_loss_percent:double \
    weight_loss_timeframe:string! \
    unable_to_weigh:string! \
    unable_to_weigh_reason:text! \
    anthropometric_notes:text! \
    --htmx

cargo loco generate scaffold assessment_dietary_history \
    assessment:references \
    meals_per_day:int \
    snacks_per_day:int \
    appetite:string! \
    appetite_change:string! \
    fluid_intake_ml_per_day:int \
    diet_type:string! \
    diet_type_other:text! \
    texture_modification:string! \
    fluid_consistency:string! \
    meal_preparation:string! \
    dietary_restrictions:text! \
    dietary_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_nutritional_screening \
    assessment:references \
    must_step1_bmi_score:int! \
    must_step2_weight_loss_score:int! \
    must_step3_acute_disease_score:int! \
    must_total_score:int! \
    must_risk_category:string! \
    acutely_ill:string! \
    no_nutritional_intake_days:int \
    screening_date:date \
    screened_by:string! \
    nutritional_screening_notes:text! \
    --htmx

cargo loco generate scaffold assessment_swallowing_oral_health \
    assessment:references \
    swallowing_difficulty:string! \
    dysphagia_severity:string! \
    dysphagia_type:string! \
    choking_episodes:string! \
    coughing_during_meals:string! \
    salt_referral:string! \
    dental_problems:string! \
    dental_problem_details:text! \
    dentures:string! \
    dentures_fit_well:string! \
    oral_pain:string! \
    dry_mouth:string! \
    oral_thrush:string! \
    swallowing_oral_notes:text! \
    --htmx

cargo loco generate scaffold assessment_gastrointestinal_function \
    assessment:references \
    nausea:string! \
    vomiting:string! \
    vomiting_frequency:string! \
    diarrhoea:string! \
    diarrhoea_frequency:string! \
    constipation:string! \
    abdominal_pain:string! \
    abdominal_bloating:string! \
    stoma:string! \
    stoma_type:string! \
    bowel_surgery:string! \
    bowel_surgery_details:text! \
    gi_function_notes:text! \
    --htmx

cargo loco generate scaffold assessment_food_allergies_intolerances \
    assessment:references \
    has_food_allergies:string! \
    has_food_intolerances:string! \
    coeliac_disease:string! \
    lactose_intolerance:string! \
    has_drug_allergies:string! \
    anaphylaxis_history:string! \
    anaphylaxis_details:text! \
    epipen_available:string! \
    allergy_details:text! \
    intolerance_details:text! \
    drug_allergy_details:text! \
    food_allergy_notes:text! \
    --htmx

cargo loco generate scaffold assessment_nutritional_requirements \
    assessment:references \
    estimated_energy_kcal_per_day:int \
    estimated_protein_g_per_day:int \
    estimated_fluid_ml_per_day:int \
    fluid_restriction:string! \
    fluid_restriction_ml:int \
    electrolyte_monitoring:string! \
    refeeding_risk:string! \
    refeeding_risk_factors:text! \
    micronutrient_supplementation:string! \
    micronutrient_details:text! \
    special_requirements:text! \
    nutritional_requirements_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_nutritional_support \
    assessment:references \
    oral_diet:string! \
    oral_nutritional_supplements:string! \
    ons_type:text! \
    ons_frequency:string! \
    enteral_feeding:string! \
    enteral_route:string! \
    enteral_feed_type:text! \
    enteral_rate_ml_per_hour:int \
    enteral_hours_per_day:int \
    parenteral_nutrition:string! \
    parenteral_type:string! \
    parenteral_details:text! \
    food_fortification:string! \
    nutritional_support_notes:text! \
    --htmx

cargo loco generate scaffold assessment_care_plan_monitoring \
    assessment:references \
    nutritional_goals:text! \
    weight_monitoring_frequency:string! \
    food_chart_required:string! \
    fluid_balance_chart_required:string! \
    dietitian_referral:string! \
    salt_referral:string! \
    reassessment_date:date \
    reassessment_frequency:string! \
    escalation_plan:text! \
    discharge_nutrition_plan:text! \
    patient_education_provided:string! \
    patient_education_details:text! \
    care_plan_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    must_total_score:int! \
    must_risk_category:string! \
    overall_risk_level:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
